<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --taskbar-bg: #2d2d2d;
            --window-bg: #303030;
            --text-color: #e0e0e0;
            --accent-color: #e95420; /* Ubuntu orange-ish */
            --border-color: #444;
        }

        * { box-sizing: border-box; user-select: none; }

        body, html {
            margin: 0; padding: 0; height: 100%; width: 100%; overflow: hidden;
            font-family: 'Ubuntu', 'Segoe UI', sans-serif;
            background-color: var(--bg-color);
            color: var(--text-color);
        }

        /* Desktop Area */
        #desktop {
            width: 100vw; height: calc(100vh - 48px); /* Leave room for taskbar */
            background: linear-gradient(135deg, #2b32b2 0%, #1488cc 100%);
            position: relative;
        }

        /* Taskbar */
        #taskbar {
            height: 48px;
            width: 100%;
            background-color: var(--taskbar-bg);
            border-top: 1px solid #000;
            display: flex;
            align-items: center;
            padding: 0 10px;
            box-shadow: 0 -2px 5px rgba(0,0,0,0.5);
        }

        .launcher {
            width: 48px; height: 48px;
            margin-right: 8px;
            border-radius: 6px;
            display: flex;
            justify-content: center;
            align-items: center;
            cursor: pointer;
            transition: background 0.2s;
            font-size: 24px;
        }

        .launcher:hover { background-color: #444; }
        .launcher.active { background-color: #555; border-bottom: 3px solid var(--accent-color); }

        /* Icons */
        #icon-files { color: #e95420; }
        #icon-notepad { color: #fff; }

        /* Windows */
        .window {
            position: absolute;
            background-color: var(--window-bg);
            border: 1px solid #000;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex;
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
            border-radius: 4px;
        }

        .window-header {
            height: 32px;
            background-color: #454545;
            display: flex;
            align-items: center;
            padding-left: 8px;
            cursor: default; /* Simplified for this task */
        }

        .win-close {
            width: 16px; height: 16px;
            background-color: #c0392b;
            border-radius: 50%;
            margin-left: auto;
            display: flex; justify-content: center; align-items: center;
            font-size: 10px; color: white; cursor: pointer;
        }
        .win-close:hover { background-color: #e74c3c; }

        /* Files App Specifics */
        #files-window { top: 50px; left: 50px; width: 600px; height: 400px; }

        .file-toolbar {
            padding: 8px;
            background-color: #3c3c3c;
            border-bottom: 1px solid var(--border-color);
            display: flex; align-items: center; gap: 10px;
        }

        #files-path { font-family: monospace; color: #aaa; font-size: 14px; }

        .fs-item {
            padding: 5px 8px;
            cursor: pointer;
            display: flex; align-items: center; gap: 6px;
            border-radius: 3px;
        }
        .fs-item:hover { background-color: #4a4a4a; }
        .fs-item.folder::before { content: '📁'; font-size: 12px; }
        .fs-item.file::before { content: '📄'; font-size: 12px; }

        /* Notepad App Specifics */
        #notepad-window { top: 50px; left: 50px; width: 600px; height: 400px; }

        .tab-strip {
            background-color: #3c3c3c;
            display: flex;
            align-items: center;
            padding-top: 5px;
            overflow-x: auto;
            border-bottom: 1px solid var(--border-color);
        }

        .tab {
            padding: 4px 12px;
            background-color: #3c3c3c;
            color: #aaa;
            font-size: 13px;
            cursor: pointer;
            border-radius: 4px 4px 0 0;
            max-width: 150px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .tab.active {
            background-color: var(--window-bg);
            color: var(--text-color);
            border-bottom: 1px solid var(--window-bg); /* Hide gap */
        }

        #new-tab-btn {
            margin-left: auto;
            padding: 4px 8px;
            background: none;
            border: none;
            color: #aaa;
            cursor: pointer;
            font-size: 12px;
        }
        #new-tab-btn:hover { color: white; }

        #editor-container { flex-grow: 1; position: relative; }

        #editor {
            width: 100%; height: 100%;
            background-color: var(--window-bg);
            color: var(--text-color);
            border: none;
            resize: none;
            outline: none;
            padding: 8px;
            font-family: 'Ubuntu Mono', monospace;
            font-size: 14px;
        }

    </style>
</head>
<body>

    <!-- Desktop Root -->
    <div id="desktop">

        <!-- Files Window -->
        <div id="files-window" class="window" style="display:none;">
            <div class="window-header">
                <span>Files</span>
                <div class="win-close" onclick="closeWindow('files-window')">×</div>
            </div>
            <div class="file-toolbar">
                <button id="files-up" style="background:none; border:none; cursor:pointer; color:#aaa;">↑</button>
                <span id="files-path">/</span>
            </div>
            <div id="files-list" style="padding: 10px; overflow-y: auto;">
                <!-- Content injected by JS -->
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window" style="display:none;">
            <div class="window-header">
                <span>Notepad</span>
                <div class="win-close" onclick="closeWindow('notepad-window')">×</div>
            </div>
            <div class="tab-strip" id="tabs">
                <!-- Tabs injected by JS -->
            </div>
            <button id="new-tab" style="margin: 5px; background:none; border:none; color:#aaa; cursor:pointer;">+ New Tab</button>
            <div id="editor-container">
                <textarea id="editor" placeholder="Type here..."></textarea>
            </div>
        </div>

    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <div class="launcher" id="open-files" onclick="openWindow('files-window')">
            <span id="icon-files">📂</span>
        </div>
        <div class="launcher" id="open-notepad" onclick="openWindow('notepad-window')">
            <span id="icon-notepad">📝</span>
        </div>
    </div>

    <script>
        // --- File System Data Structure ---
        const fileSystem = {
            '/': ['bin', 'etc', 'home', 'usr', 'var'],
            '/bin': [],
            '/etc': [],
            '/home': ['user'],
            '/home/user': ['Documents', 'Downloads', 'Pictures'],
            '/home/user/Documents': ['resume.txt', 'notes.md'],
            '/home/user/Downloads': ['image.png', 'setup.sh'],
            '/home/user/Pictures': ['vacation.jpg']
        };

        // --- State Management ---
        let currentPath = '/';

        // Notepad State
        let tabs = []; 
        let activeTabId = null;

        // --- Initialization ---
        window.onload = function() {
            renderFiles();
            loadNotepadState();

            // Event Listeners for Files App
            document.getElementById('files-up').addEventListener('click', goUp);

            // Event Listeners for Notepad App
            document.getElementById('new-tab').addEventListener('click', createNewTab);
            document.getElementById('editor').addEventListener('input', saveNotepadState);
        };

        // --- Window Management ---
        function openWindow(id) {
            const win = document.getElementById(id);
            if (win.style.display === 'none') {
                win.style.display = 'flex';
                bringToFront(win);
            }
        }

        function closeWindow(id) {
            const win = document.getElementById(id);
            win.style.display = 'none';

            // If closing notepad, save state before hiding
            if (id === 'notepad-window') {
                saveNotepadState();
            }
        }

        function bringToFront(element) {
            const allWindows = document.querySelectorAll('.window');
            allWindows.forEach(w => w.style.zIndex = 1);
            element.style.zIndex = 2;
        }

        // --- Files App Logic ---
        function renderFiles() {
            const list = document.getElementById('files-list');
            const pathDisplay = document.getElementById('files-path');

            list.innerHTML = '';
            pathDisplay.innerText = currentPath;

            const items = fileSystem[currentPath];
            if (!items) return;

            items.forEach(name => {
                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item folder'; // Treat all as folders for simplicity or add logic
                itemDiv.innerText = name;

                // Double click to enter
                itemDiv.addEventListener('dblclick', () => {
                    if (fileSystem[currentPath + '/' + name]) {
                        currentPath += '/' + name;
                        renderFiles();
                    } else {
                        // If it's a file (empty array in our structure), just show it
                        const itemDiv = document.createElement('div');
                        itemDiv.className = 'fs-item file';
                        itemDiv.innerText = name;
                        list.appendChild(itemDiv);
                    }
                });

                list.appendChild(itemDiv);
            });
        }

        function goUp() {
            if (currentPath === '/') return;

            // Remove last segment
            const parts = currentPath.split('/');
            parts.pop();
            currentPath = parts.join('/') || '/';
            renderFiles();
        }

        // --- Notepad App Logic ---

        function loadNotepadState() {
            const saved = localStorage.getItem('notepad_data');
            if (saved) {
                tabs = JSON.parse(saved);
            } else {
                // Default state
                createNewTab(); 
            }

            renderTabs();
            updateEditorContent();
        }

        function saveNotepadState() {
            localStorage.setItem('notepad_data', JSON.stringify(tabs));
        }

        function createNewTab() {
            const id = Date.now().toString();
            tabs.push({
                id: id,
                title: 'Untitled-' + (tabs.length + 1),
                content: ''
            });

            renderTabs();
            switchToTab(id);
        }

        function deleteTab(e, id) {
            e.stopPropagation(); // Prevent clicking tab itself

            if (tabs.length === 1) return; // Don't allow deleting last tab

            tabs = tabs.filter(t => t.id !== id);

            if (activeTabId === id) {
                const newActiveIndex = tabs.findIndex(t => t.id === activeTabId);
                if (newActiveIndex > -1) {
                    switchToTab(tabs[newActiveIndex].id);
                } else {
                    // Switch to last tab if we just deleted the active one
                    switchToTab(tabs[tabs.length - 1].id);
                }
            }

            renderTabs();
            updateEditorContent();
        }

        function renderTabs() {
            const container = document.getElementById('tabs');
            container.innerHTML = '';

            tabs.forEach(tab => {
                const tabEl = document.createElement('div');
                tabEl.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
                tabEl.innerText = tab.title;

                // Click to switch
                tabEl.addEventListener('click', () => switchToTab(tab.id));

                // Close button for tab (X)
                const closeBtn = document.createElement('span');
                closeBtn.style.marginLeft = 'auto';
                closeBtn.style.cursor = 'pointer';
                closeBtn.innerText = '×';
                closeBtn.style.color = '#aaa';
                closeBtn.onclick = (e) => deleteTab(e, tab.id);

                tabEl.appendChild(closeBtn);
                container.appendChild(tabEl);
            });
        }

        function switchToTab(id) {
            activeTabId = id;
            renderTabs(); // Re-render to update active class
            updateEditorContent();
        }

        function updateEditorContent() {
            const editor = document.getElementById('editor');
            if (activeTabId) {
                const tab = tabs.find(t => t.id === activeTabId);
                if (tab) {
                    editor.value = tab.content;
                }
            }
        }

    </script>
</body>
</html>
